import os

def get_ls_result(dir_path: str) -> str:
    if '..' in dir_path or not os.path.isabs(dir_path):
        return ""
    abs_path = os.path.abspath(dir_path)
    safe_dir = "/home/user/"
    if not abs_path.startswith(safe_dir):
        return ""
    try:
        with os.scandir(abs_path) as entries:
            result = []
            for entry in entries:
                entry_path = os.path.join(abs_path, entry.name)
                stats = entry.stat()
                result.append(f"{entry.name} {stats.st_size} {stats.st_mtime}")
            return "\n".join(result)
    except Exception:
        return ""
